#[get("/proxy")]
async fn proxy_handler(
    _req: HttpRequest,
    query: web::Query<ProxyQuery>,
    client: web::Data<Client>,
) -> HttpResponse {
    let target_url = &query.url;

    // Validate the URL against SSRF
    if let Err(reason) = is_safe_url(target_url) {
        return HttpResponse::BadRequest().body(format!("Blocked request: {}", reason));
    }

    // Perform the request
    match client
        .get(target_url)
        .timeout(std::time::Duration::from_secs(10))
        .send()
        .await
    {
        Ok(response) => {
            let status = response.status();
            let headers = response.headers().clone();

            match response.bytes().await {
                Ok(body) => {
                    let mut builder = HttpResponse::build(status);

                    // Forward safe headers
                    let safe_headers = ["content-type", "content-length", "cache-control", "etag", "last-modified"];
                    for header_name in &safe_headers {
                        if let Some(value) = headers.get(*header_name) {
                            if let Ok(v) = value.to_str() {
                                builder.insert_header((*header_name, v.to_string()));
                            }
                        }
                    }

                    builder.body(body)
                }
                Err(e) => {
                    HttpResponse::BadGateway().body(format!("Failed to read response body: {}", e))
                }
            }
        }
        Err(e) => {
            // Check if a redirect led to an internal IP (reqwest may follow redirects)
            HttpResponse::BadGateway().body(format!("Failed to fetch URL: {}", e))
        }
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    println!("Starting webhook proxy on http://127.0.0.1:8080");

    // Build a reqwest client that does NOT follow redirects automatically
    // to prevent SSRF via redirect to internal IPs
    let client = Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .timeout(std::time::Duration::from_secs(15))
        .build()
        .expect("Failed to build HTTP client");

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(client.clone()))
            .service(proxy_handler)
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_blocks_localhost() {
        assert!(is_safe_url("http://localhost/secret").is_err());
        assert!(is_safe_url("http://127.0.0.1/secret").is_err());
        assert!(is_safe_url("http://[::1]/secret").is_err());
    }

    #[test]
    fn test_blocks_private_ips() {
        assert!(is_safe_url("http://10.0.0.1/internal").is_err());
        assert!(is_safe_url("http://172.16.0.1/internal").is_err());
        assert!(is_safe_url("http://192.168.1.1/internal").is_err());
    }

    #[test]
    fn test_blocks_metadata_endpoints() {
        assert!(is_safe_url("http://169.254.169.254/latest/meta-data/").is_err());
        assert!(is_safe_url("http://metadata.google.internal/computeMetadata/v1/").is_err());
    }

    #[test]
    fn test_blocks_disallowed_schemes() {
        assert!(is_safe_url("file:///etc/passwd").is_err());
        assert!(is_safe_url("ftp://example.com/file").is_err());
        assert!(is_safe_url("gopher://example.com/").is_err());
    }

    #[test]
    fn test_blocks_credentials_in_url() {
        assert!(is_safe_url("http://user:pass@example.com/").is_err());
    }

    #[test]
    fn test_allows_public_urls() {
        // These should resolve to public IPs and be allowed
        assert!(is_safe_url("https://www.google.com/").is_ok());
        assert!(is_safe_url("https://api.github.com/").is_ok());
    }

    #[test]
    fn test_blocks_zero_address() {
        assert!(is_safe_url("http://0.0.0.0/").is_err());
    }

    #[test]
    fn test_private_ip_detection() {
        assert!(is_private_ip(&"127.0.0.1".parse().unwrap()));
        assert!(is_private_ip(&"10.0.0.1".parse().unwrap()));
        assert!(is_private_ip(&"172.16.0.1".parse().unwrap()));
        assert!(is_private_ip(&"192.168.0.1".parse().unwrap()));
        assert!(is_private_ip(&"169.254.169.254".parse().unwrap()));
        assert!(is_private_ip(&"0.0.0.0".parse().unwrap()));
        assert!(is_private_ip(&"::1".parse().unwrap()));

        assert!(!is_private_ip(&"8.8.8.8".parse().unwrap()));
        assert!(!is_private_ip(&"1.1.1.1".parse().unwrap()));
    }
}